-- Skills
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (61, '銅筋鉄骨', NULL, NULL, 'パッシブ', '部隊は2秒ごとに最大7700【5000】の兵力しか失わない。固定ダメージは無効化できない。部隊のクリティカル率が90%減少する。', 61);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (62, '百挫してなお屈せず', NULL, NULL, 'パッシブ', '部隊が前6秒以内にデバフ状態になるごとに、与える全ダメージが5.5%【10%】増加、最大で23%【50%】まで（武力補正）', 62);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (63, '乾坤を策定', NULL, NULL, 'パッシブ', '部隊は【挑発】・【鈍足】状態を無効化する。2秒以内に3未満の部隊から攻撃を受けた場合、主将が与える全ダメージが知力補正で6%【15%】上昇。3以上の部隊から攻撃を受けた場合、部隊が受ける全ダメージが11％【20%】減少。5以上の部隊から攻撃を受けた場合、全ての増減ダメージ効果が無効化される。', 63);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (64, '杙道を明修', NULL, NULL, 'パッシブ', '部隊が移動中は【挑発】・【鈍足】状態を無効化。さらに戦闘に突入し初回ダメージ発生後、部隊の与える全ダメージが12%【30%】増加（知力補正）。増加効果は4秒ごとに1%減少', 64);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (65, '飛火矢', '弓のみ', NULL, 'パッシブ', '通常攻撃時、10%の確率で対象を【灼傷】状態（ダメージ率120%【300%】）にし、4秒間持続。対象が林地にいる場合、燃灼発生確率が30%まで上昇し、通常攻撃で対象タイルが【燃焼】状態（ダメージ率70%【160%】4秒間持続）となる。対象が燃焼または燃灼状態の場合、通常攻撃で50%の確率で【鈍足】状態となり、移動速度が22%【40%】低下する。4秒間持続', 65);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (66, '高所より敵を防ぐ', NULL, '弓のみ', 'パッシブ', '自身部隊が与える全ダメージが16%【25%】増加します。部隊の高度が目標部隊より高い場合、与える全ダメージが27%【45%】まで増加します。（武力補正）', 66);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (67, '和歌', NULL, NULL, '能動', '30%の確率で発動し、敵部隊に知攻ダメージ 65%【】を与え、部隊に【武攻ダメージ増加】状態を付与する。武攻5%（知力補正）上昇し、1部隊につき最大5回まで重ね掛け可能', 67);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (68, '剣舞', NULL, NULL, 'パッシブ', '部隊が攻撃する際、直前2秒間と同じ目標を攻撃している場合、部隊の与える全ダメージが2%上昇し、最大7【25】回まで重複可能。攻撃目標が異なる場合、このダメージ上昇効果はリセットされる。', 68);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (69, '周を補け紂を討つ', NULL, NULL, 'パッシブ', '主将が怒気技を発動した際、同時に敵部隊1体に知攻ダメージ 380%【1100%】を与え、自身の怒気を11【20】回復します。', 69);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (70, '休養生息', NULL, NULL, 'パッシブ', '2秒ごとに部隊の兵力が一定量回復する（回復率 65%【200%】知力補正）。非戦闘時にも回復する。', 70);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (71, '百発百中', '弓のみ', NULL, 'パッシブ', '部隊の射程が1減少し、距離2以下の目標に与える全ダメージが15%【60%】増加、命中率55%【100％】上昇します。', 71);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (72, '百歩先の柳を射抜く', NULL, '弓のみ', 'パッシブ', '自身部隊の射程が1増加し、距離が3以上の敵部隊に対して全ダメージが1%【10%】増加します。（武力補正）', 72);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (73, '月を隠す美貌', NULL, NULL, 'パッシブ', '自身が【通常攻撃不可】状態に陥る代償として、部隊アクティブスキル発動率が5.5%【10%】増加します。', 73);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (74, '驚鴻の舞', NULL, NULL, 'パッシブ', '部隊のアクティブスキル発動率が4%【13%】増加します。（知力補正）', 74);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (75, '弦鳴れば甲も破れる', NULL, NULL, '能動', '21%【30%】の確率で発動し、敵部隊に武攻ダメージ 60%【150%】を与え、【被ダメージ増加】状態にする。この状態中、受ける全ダメージが1%【10%】上昇し、2秒間持続', 75);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (76, '戦場の激戦', NULL, NULL, 'パッシブ', '部隊が与える全てのダメージが3.4%【7】（武力補正）上昇させる。
隣接に存在する敵部隊1部隊につき、追加で2.3%【5%】上昇し、最大で6.9%【15%】まで追加上昇可能。
受ける全てのダメージを3.4%【7%】（胆力補正）軽減し、隣接する味方または友軍部隊1部隊につき、
追加で2.3%【5%】軽減し、最大で6.9%【15%】まで追加軽減可能。', 76);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (77, '九つの攻伐策', NULL, NULL, '能動', '25%の確率で発動し、敵部隊に知攻ダメージ 245%【650%】を与える。9回目以降はこのスキルの基本発動率が戦闘離脱まで半分になる。', 77);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (78, '百工の祖', NULL, NULL, 'パッシブ', '同盟器械操作中、2秒ごとに耐久を5【50】回復（知力補正）、戦闘中は回復効果が3倍になる。', 78);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (79, '珠玉の如き結び付き', NULL, NULL, '能動', '25%の確率で発動し、自身が相手主将の現在の最大属性の6.5%【20%】を獲得し、対象を【属性減少】状態にする。最大属性を3%【7.5%】減少させ、4秒間持続', 79);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (80, '枚を枚め心静か', NULL, NULL, 'パッシブ', '部隊が2秒間ダメージを受けず、枚つ同高度で隣接に敵部隊がいない場合、部隊が与える全てのダメージを11%【20%】（武力補正）上昇させ、クリティカル率+6%【15%】', 80);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (81, '琴瑟の調べ', NULL, NULL, 'パッシブ', '主将が怒気スキルを発動すると、部隊がダメージ量x 53%【125%】分の兵力を回復する。', 81);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (82, '明妃', NULL, NULL, 'パッシブ', '主将の与える全ダメージが24%【60%】増加（知力補正）。副将の与える全ダメージが29%【20%】減少', 82);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (83, '秋毫を明らかに察する', NULL, NULL, '能動', '26%【35%】の確率で発動し、敵部隊の主将または副将を【機会利用】状態にし、持続2秒。
対象がアクティブスキル発動に失敗した場合、知攻ダメージ 190%【370%】を受ける。', 83);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (84, '力を蓄え発するを待つ', NULL, NULL, 'パッシブ', '部隊の兵力が初めて兵力上限の90%/70%/50%/30%を下回った時、クリティカル率が22%【40%】増加し、アクティブおよび連鎖スキルの発動率が11.5%【25%】（知力補正）上昇する。4秒間持続。さらに【ダメージ無効】状態を獲得し、4秒間持続する。', 84);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (85, '辺境を震わす威名', NULL, NULL, 'パッシブ', '自身の通常攻撃ダメージ21%【30%】増加し、自身の連鎖ダメージが21%【30%】増加する。これらのダメージ増加効果は2秒ごとに0.5%ずつ減少し、最大10%まで減少する。戦闘状態を離脱するまで持続する。', 85);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (86, '白刃戦', NULL, NULL, 'パッシブ', '部隊の与える全ダメージが12.5%【35%】増加（武力補正）。距離が1を超えるごとに距離1ごとに効果が10%減少', 86);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (87, '摂政として威を立てる', NULL, NULL, '能動', '12%【30%】の確率で発動し、敵部隊を【服従】状態にする。この状態の目標を攻撃時、攻撃側アクティブスキル・連鎖スキル発動率5%上昇。重複、置換不可。持続時間4秒', 87);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (88, '甲冑を着て督戦', NULL, NULL, 'パッシブ', '部隊の士気+6【+15】（知力補正）、敵部隊の士気が低い場合、1点の士気差ごとに部隊が与える全ダメージが1.5%増加。非プレイヤー部隊との戦闘時、士気差は固定で11【20】となる。', 88);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (89, '臥薪嘗胆', NULL, NULL, 'パッシブ', '部隊が受ける通常攻撃ダメージが16%【25】減少。さらに通常攻撃ダメージを受けるたびに、自身のアクティブスキル発動率が0.5％【5%】上昇（最大4回まで重複可能。2秒間', 89);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (90, '士気を鼓舞', NULL, NULL, 'パッシブ', '部隊の士気+5.5【+10】。士気が100以上の時、与える全ダメージが11%【20%】上昇（知力補正）', 90);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (91, '百戦先んず', NULL, NULL, '怒気技', '主将時、怒気が100以上の時、全ての怒気を消費し、敵部隊に武攻ダメージ 570%【1200%】（怒気補正）を与え、さらに22%【40%】の確率で部隊が【ダメージ無効】状態になり、2秒間持続', 91);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (92, '陥陣先鋒', NULL, NULL, 'パッシブ', '部隊が与える全てのダメージを5.5%【10%】（武力補正）上昇させ、【隣接】に存在する敵部隊1部隊につき、追加で2.5%【7%】上昇し、最大で16%【25%】まで追加上昇する。', 92);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (93, '弓は霹靂の如し', '弓のみ', NULL, 'パッシブ', '自身のクリティカル率+6％【+15%】。敵主将+副将の胆力が125【350】未満の場合、さらにクリティカル率+5.5%【+10%】', 93);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (94, '雷霆の威', NULL, NULL, 'パッシブ', '部隊のクリティカル率+3%【12%】、クリティカルダメージ+25%【70%】（武力補正）', 94);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (95, '吏治を整備', NULL, NULL, 'パッシブ', '主政官に任命されている場合、全官員の内政が+12【+30%】', 95);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (96, '乾綱独断', NULL, NULL, 'パッシブ', '部隊が敵主将から受ける全ダメージが22%【40％】減少（知力補正）', 96);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (97, '荒地開墾令', NULL, NULL, 'パッシブ', '糧秣官に任命されている場合、食糧産出量が1%【10%】増加（内政補正）', 97);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (98, '軍功により爵位進む', NULL, NULL, 'パッシブ', '部隊が戦闘で獲得する軍功が3.5%【8%】増加（内政補正）', 98);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (99, '府兵制', NULL, NULL, 'パッシブ', '募兵使に任命されている場合、予備兵の徴兵速度が5.5%【10%】上昇', 99);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (100, '戦場に精通', NULL, NULL, 'パッシブ', '部隊が戦闘で獲得する経験値が11%【20%】増加（内政補正）', 100);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (101, '豆を撒きて兵と成す', NULL, NULL, '能動', '31%【40%】の確率で発動し、部隊が追加で兵力を獲得する（回復率165%【300%】知力補正）。4秒後にこの兵力は消失し、兵力損失時はこの兵力から優先して消費され、負傷兵は発生しない。', 101);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (102, '勝ちに乗じて突進', NULL, '馬のみ', 'パッシブ', '部隊が移動中の目標に与えるダメージが22%【40%】（知力補正）上昇し、ダメージを与えた後、部隊の移動速度が110【200】上昇 4秒持続・重複不可。また部隊が移動中の場合、受ける全ダメージが22%【40】減少する。', 102);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (103, '低質蘭心', NULL, NULL, 'パッシブ', '部隊が攻撃目標と見なされた際、ダメージを与えた部隊の全武将のアクティブスキル発動率6%【15%】低下する（効果は重複不可）2秒間持続', 103);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (104, '鳳凰を求む', NULL, NULL, 'パッシブ', '相性有利な兵種にダメージを与えるとダメージ値x7%【25％】分の兵力を回復', 104);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (105, '鼓を打ち陣を破る', NULL, NULL, '能動', '30%の確率で発動し、敵部隊に武攻ダメージ 160%【250%】を与える。また自身のアクティブスキル発動率を10%上昇。持続時間4秒。この発動率上昇効果は重複不可。', 105);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (106, '女性軍', NULL, NULL, 'パッシブ', '敵将が男性の場合、部隊が受ける武攻ダメージが22%【40%】減少（武力補正）。ただし、弓兵及び投石からのダメージは減少しない。', 106);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (107, '連撃', NULL, NULL, '能動', '25%【52%】の確率で発動し、自身に【連撃】状態を付与。2秒間持続', 107);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (108, '槍の反突', NULL, NULL, 'パッシブ', '4秒以内に対象部隊からダメージを受けた場合、自身部隊がその部隊に与える連鎖ダメージが13%【40%】増加する（武力補正）', 108);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (109, '天下に独り戦う', NULL, NULL, '能動', '11%【29%】の確率で発動し、自身の【円形範囲】内の2部隊の敵部隊を【挑発】状態にし、2秒間持続する', 109);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (110, '烈火城を焼く', NULL, NULL, 'パッシブ', '部隊の主将および副将が建築物にダメージを与える際、攻撃者自身の知力x40%【85%】の追加ダメージ加算を得る。', 110);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (111, '強弩猛射', '弓のみ', NULL, 'パッシブ', '部隊が距離2以下の目標に与える全ダメージが12%【30%】増加する。', 111);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (112, '矢は必中', NULL, '弓のみ', 'パッシブ', '部隊の命中率+6.5【20%】。距離3以下の目標に与える全ダメージが5.5%【19%】増加する（武力補正）', 112);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (113, '帝の親征', NULL, NULL, '連鎖', '通常攻撃後、25%の確率で敵部隊に知攻ダメージ 75%【210%】を与え、さらに敵の怒気を5減少させる。', 113);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (114, '建安の気骨', NULL, NULL, 'パッシブ', '部隊【隣接】範囲に存在する敵部隊1部隊につき、怒気が2秒毎に0.6【1.5】ポイント追加回復し、最大で2秒毎に10ポイントまで追加可能。', 114);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (115, '火牛の陣', NULL, NULL, '怒気技', '主将時に怒気100以上の時、全怒気を消費し、前方【扇形範囲】内の最大3部隊の敵部隊に知攻ダメージ 440%【800%】（怒気補正）を与え、敵部隊が1部隊多いごとにダメージ率が80%減少する。', 115);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (116, '城外にて敵を拒む', NULL, NULL, 'パッシブ', '部隊が受ける全てのダメージを0.5%【5%】（胆力補正）軽減し、【隣接】に存在する味方または友軍部隊1部隊につき、追加で2.5%【7%】軽減し、最大で11%【20%】まで追加軽減可能', 116);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (117, '鳳撃', NULL, NULL, '能動', '30%の確率で発動し、敵部隊に武攻ダメージ 95%【230％】を与える', 117);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (118, '鳳舞', NULL, NULL, 'パッシブ', '部隊が受ける全ダメージが11%【20%】減少', 118);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (119, '忠義智謀を尽くす', NULL, NULL, '能動', '30%の確率で発動し、敵部隊に知攻ダメージ 105%【285％】を与え、自身の知力を20減少させる。2秒間持続', 119);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (120, '王佐の才', NULL, NULL, 'パッシブ', '主将が与える全ダメージが12%【30%】増加します。（知力補正）', 120);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (121, '塞外平定', NULL, NULL, '連鎖', '通常攻撃後、25%の確率で敵部隊に武攻ダメージ 85%【220%】を与える。自身が【連撃】状態の場合、このスキルの発動確率がさらに5%上昇。', 121);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (122, '白馬義従', NULL, '馬のみ', 'パッシブ', '移動速度+10【+46】、部隊が弓兵から受けるダメージが18%【45%】減少する。', 122);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (123, '済世の略', NULL, NULL, 'パッシブ', '自身が通常攻撃を2回行うごとに、自身の武力ｘ13%【40％】の兵力を回復する', 123);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (124, '群雄を睥睨', NULL, NULL, 'パッシブ', '部隊が自部隊より高低差が低い敵部隊に対して与える全ダメージが6.5%【20%】増加する（武力補正）', 124);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (125, '軍制厳然', NULL, NULL, 'パッシブ', '部隊が受ける連鎖ダメージが9%【27%】減少する。', 125);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (126, '長駆直入', NULL, NULL, 'パッシブ', '部隊移動中に受ける全てのダメージを12%【30%】（胆力補正）軽減し、【隣接】に敵部隊のみ存在する場合、与える全てのダメージを6%【15%】（武力補正）上昇させる。', 126);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (127, '起死回生', NULL, NULL, '能動', '21%【30%】の確率で発動し、部隊の兵力を一定量回復（回復率65%【200%】知力補正）。兵力が40%未満の場合、回復率がさらに55%【100%】上昇。', 127);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (128, '俗に応じて変ず', NULL, NULL, 'パッシブ', '部隊の回復効果が24%【60%】上昇します（知力補正）', 128);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (129, '屯兵', NULL, NULL, 'パッシブ', '戦闘開始後、2秒ごとに自身の胆力ｘ12.5%【26%】の兵力を回復する。', 129);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (130, '攻撃を以て守りと為す', NULL, NULL, 'パッシブ', '部隊が与える全ダメージが5.5%【10%】増加する（武力補正）。受ける全ダメージ5.5%【10%】減少する（胆力補正）', 130);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (131, '狂瀾覆し', NULL, NULL, '能動', '21%【30%】の確率で発動し、敵部隊に武攻ダメージ 80%【170%】を与える。このダメージは敵の23%【50%】胆力を無視。', 131);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (132, '勇猛果敢', NULL, NULL, 'パッシブ', '戦闘開始後、部隊の全武将の武力+5.5【+10】、通常攻撃ダメージが12%【30%】増加する（武力補正）', 132);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (133, '筆を捨て軍に従う', NULL, NULL, 'パッシブ', '戦闘開始後、自身の武力が基礎知力ｘ8%【26%】増加する。', 133);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (134, '万里にて侯爵と成す', NULL, NULL, 'パッシブ', '部隊の移動速度+33【+60】、孤立した敵部隊に与えるダメージが8.5%【22%】増加する（知力補正）', 134);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (135, '見抜き', NULL, NULL, '能動', '11%【29%】の確率で発動し、部隊に【見抜き】状態を付与し、いずれかのアクティブスキルによるダメージを2秒間受けた後、この状態が解除される。(見抜き：アクティブスキルの被ダメ大幅減少）', 135);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (136, '木石も威を生す', NULL, '兵器のみ', 'パッシブ', '衝車・投石隊の部隊操作時、与える全ダメージが55%【145%】増加する。', 136);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (137, '三軍奮戦', '弓以外', NULL, 'パッシブ', '部隊壊滅時,【円形範囲】内の最大3敵部隊に物理ダメージ 700%【2500%】、100秒以内に兵力50%以上損失時+320%【+950%】。出撃時兵力基準。NPC戦：傷病率-50%/プレイヤー戦：傷病率-5%', 137);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (138, '福将', NULL, NULL, 'パッシブ', '部隊のクリティカル耐性率+21%【48%】（胆力補正）', 138);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (139, '博識多才', NULL, NULL, 'パッシブ', '生産系の内政官を担当すると、該当する基礎資源算出が650【2000】増加する。', 139);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (140, '銅製部品', NULL, '兵器のみ', 'パッシブ', '衝車・投石時、部隊の全武将の武力+22【+40】、胆力+22【+40】', 140);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (141, '敵鋒挫き', NULL, NULL, 'パッシブ', '部隊が受けるアクティブスキルダメージが6%【15%】減少する。', 141);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (142, '堅守の意志', NULL, NULL, 'パッシブ', '部隊の士気減少速度が30%減少し、受けるアクティブスキルのダメージが7%【25%】減少', 142);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (143, '八方馬踏', NULL, NULL, '連鎖', '通常攻撃後、25%の確率で敵部隊に武攻ダメージ 75%【210%】を与える。対象兵種を克服している場合、対象部隊を【治療禁止】状態にし、4秒間持続。', 143);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (144, '遠射', NULL, '弓のみ', 'パッシブ', '自身の部隊は距離3以上の敵部隊に与える全ダメージが4%【13%】増加する。スキルLv10で自身部隊の射程が1増加し、かつ距離3以上の目標を攻撃時、命中率-15%', 144);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (145, '弦鳴り雁落つ', '弓のみ', NULL, '能動', '21%【30%】の確率で発動し、敵部隊に武攻ダメージ 90%【225%】を与える。敵部隊の高度が自身より高い場合、ダメージ率がさらに25%【70%】増加', 145);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (146, '雁射る', NULL, '弓のみ', 'パッシブ', '対象部隊の高さが自身より高い場合、主将のクリティカル率+13%【40%】（武力補正）', 146);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (147, '力借りて力を打つ', NULL, NULL, '能動', '20%【65%】の確率で発動し、部隊内の他の武将を【通常攻撃不可】状態にし、2秒間持続。自身は通常攻撃をもう1回追加で行える。', 147);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (148, '鶏の鳴き声で起きて舞う', NULL, NULL, 'パッシブ', '2秒ごとに部隊のデバフ状態を1つ解除する。戦闘開始後、部隊の全武将は100秒間アクティブスキル発動率が4.5%【9%】増加し、その後は発動率増加効果が失われ、戦闘終了まで継続する。', 148);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (149, '商聖', NULL, NULL, 'パッシブ', '交易官を担当する場合、市場取引の比率が2.5%【7%】増加する。', 149);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (150, '急流勇退', NULL, NULL, 'パッシブ', '戦闘開始後、部隊が与える全ダメージが8.5%【22%】増加（知力補正）、さらに増加しダメージ効果は10秒ごとに1%減少', 150);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (151, '速戦即決', NULL, NULL, '能動', '21%【30%】の確率で発動し、敵部隊に知攻ダメージ 85%【220%】を与える。また、戦闘開始前100秒間、ダメージ率が155%【290%】に上昇。', 151);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (152, '兵を分かち合撃', NULL, NULL, 'パッシブ', '主将は行動のたびに42%【60%】の確率で【連撃】状態を2秒間獲得し、さらに連撃を得た場合、副将が与える全ダメージが6.5%【20%】増加。2秒間持続。', 152);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (153, '論戦', NULL, NULL, '能動', '30%の確率で発動し、敵部隊に知攻ダメージ 125%【260%】を与える。15回目以降、このスキルのダメージ率は100%減少し、退場まで持続。', 153);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (154, '一気呵成', NULL, NULL, 'パッシブ', '戦闘開始後、最初の100秒間、部隊が与える全ダメージが11%【20%】増加する（知力補正）、100秒以降は全ダメージが5.5%【10%】増加し、戦闘終了まで持続する（知力補正）', 154);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (155, '金剛', NULL, NULL, 'パッシブ', '部隊が受ける全ダメージが2.4%【6%】減少', 155);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (156, '悪鎮め', NULL, NULL, 'パッシブ', '部隊の連鎖スキル発動確率 +3.5%【+8％】', 156);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (157, '大放談', NULL, NULL, '能動', '30%の確率で発動し、敵軍部隊に知攻ダメージ 65%【200%】を与える。', 157);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (158, '窮地からの生還', NULL, NULL, 'パッシブ', '部隊兵力が31%【40%】未満の時、移動速度+37【+100】、回復効果が46%【100%】増加する', 158);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (159, '暗殺', NULL, NULL, '能動', '30%の確率で発動し、武攻ダメージ 45%【180】を与え、このダメージは20%の確率でクリティカルになる。', 159);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (160, '図窮の寸鉄', NULL, NULL, 'パッシブ', '戦闘開始後、部隊が与える全ダメージが5%増加し、増加効果は4秒ごとに0.5%ずつ上昇し、最大で6%【15%】（武力補正）まで上昇する。', 160);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (161, '怒斬り', NULL, NULL, '怒気技', '主将担当時、怒気が100以上の際、全怒気を消費し、敵部隊に武攻ダメージ 600%【1050%】（怒気補正）を与える。', 161);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (162, '威名', NULL, NULL, 'パッシブ', '部隊が与える全ダメージが1%【5.5%】上昇、自身の武力が敵軍師より高い場合は効果が2%【11%】上昇', 162);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (163, '旗揚げ', NULL, NULL, '連鎖', '通常攻撃後、25%の確率で敵部隊に武攻ダメージ 60%【195％】を与える。', 163);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (164, '鴻鵠の志', NULL, NULL, 'パッシブ', '部隊が与える通常攻撃ダメージが17%【35%】増加し、兵力が敵部隊より少ない場合は34%【70%】増加となる。', 164);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (165, '委壌', NULL, NULL, '能動', '35%の確率で発動し、主将が与える全ダメージが13%【40%】上昇、2秒間持続', 165);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (166, '安楽公', NULL, NULL, 'パッシブ', '戦闘開始後、部隊全武将の武力・知力・胆力+6【+15】', 166);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (167, '治療', NULL, NULL, '能動', '30%の確率で発動し、部隊の兵力を一定量回復 110%【200%】知力補正', 167);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (168, '林下の風雅', NULL, NULL, 'パッシブ', '部隊が受ける全ダメージが1%【5.5%】減少し、自身の知力が敵部隊軍師より高い場合は2%【11%】減少となる。', 168);

